1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	};
67	
68	const itemBasePremium = (item: Item): number =>
69	  ITEM_BASE_PREMIUMS[item.type] ?? 0;
70	
71	const itemPremiumWithFirstInsurance = (item: Item): number => {
72	  const base = itemBasePremium(item);
73	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
74	};
75	
76	const quotePremium = (items: Item[]): number => {
77	  const policyTotal = items.reduce(
78	    (sum, item) => sum + itemPremiumWithFirstInsurance(item),
79	    0,
80	  );
81	  return roundUp(policyTotal) + PROCESSING_FEE;
82	};
83	
84	export const processScenario = (scenario: Scenario): ScenarioResult => {
85	  const results: StepResult[] = scenario.steps.map((step) => {
86	    if (step.op === "quote") {
87	      return { premium: quotePremium(step.items) };
88	    }
89	    return { payout: 0, remainingCap: 0 };
90	  });
91	  return { results };
92	};
